DROP TABLE IF EXISTS `picking_list`;
CREATE TABLE `picking_list`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主キーID',
  `shipping_no_p` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '出荷番号＋製品コード（一意キー）',
  `shipping_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT 'パレット番号（出荷番号）',
  `product_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '製品コード',
  `product_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT '製品名',
  `confirmed_boxes` int NOT NULL DEFAULT 0 COMMENT '指示箱数',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uq_shipping_no_p`(`shipping_no_p` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5725782 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin COMMENT = 'ピッキング指示リスト' ROW_FORMAT = Dynamic;

